const { androidWebview, iosWebview, unknownWebview } = require('../regexps/ua/generic-webviews');
const identifiedInApps = require('../regexps/ua/identified-in-apps');

const isGenericWebview = [
  androidWebview,
  iosWebview,
  unknownWebview,
].join('|');

const isIdentifiedInApp = Object.values(identifiedInApps).join('|');

const isInApp = `${isGenericWebview}|${isIdentifiedInApp}`;

module.exports = {
  isInApp,
};
